function sendHeartbeat() {
    fetch("heartbeat.php");
}

sendHeartbeat();
setInterval(sendHeartbeat, 5000);


const messagesBox = document.getElementById("messages");
const messageInput = document.querySelector(".message-input");

const receiverId = messagesBox.dataset.receiverId;

const messageForm = document.querySelector(".message-form");

messageForm.addEventListener("submit", async function (event) {
    event.preventDefault();

    const message = messageInput.value.trim();

    if (message === "") return;

    const formData = new FormData(messageForm);

    try {
        await fetch("send-message.php", {
            method: "POST",
            body: formData
        });

        messageInput.value = "";

        await loadMessages();

        messagesBox.scrollTop = messagesBox.scrollHeight;

        messageInput.focus();

    } catch (error) {
        console.error("Error sending message:", error);
    }
});

function scrollToBottom() {
    messagesBox.scrollTop = messagesBox.scrollHeight;
}


let lastMessagesHTML = "";

function loadMessages() {
    return fetch(`fetch-messages.php?receiver_id=${receiverId}`)
        .then(response => response.text())
        .then(data => {

            if (data !== lastMessagesHTML) {

                messagesBox.innerHTML = data;
                lastMessagesHTML = data;

                scrollToBottom();
            }
        });
}


loadMessages();

setInterval(loadMessages, 1000);


/* Keep typing focus */

document.addEventListener("keydown", function (event) {

    if (
        document.activeElement !== messageInput &&
        !event.metaKey &&
        !event.ctrlKey &&
        !event.altKey
    ) {
        messageInput.focus();
    }

});


const onlineStatus = document.querySelector(".online-status");

function checkUserStatus() {

    if (!onlineStatus || !receiverId) {
        return;
    }

    fetch(`user-status.php?user_id=${receiverId}`)
        .then(response => response.text())
        .then(status => {

            status = status.trim();

            if (status === "online") {

                onlineStatus.textContent = "Online";

                onlineStatus.classList.add("online");
                onlineStatus.classList.remove("offline");

            } else {

                onlineStatus.textContent = "Offline";

                onlineStatus.classList.add("offline");
                onlineStatus.classList.remove("online");

            }

        });

}

checkUserStatus();

setInterval(checkUserStatus, 3000);

* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

html,
body {
    width: 100%;
    height: 100%;
}

body {
    overflow: hidden;

    font-family:
        -apple-system,
        BlinkMacSystemFont,
        "Segoe UI",
        Roboto,
        sans-serif;

    background: #f5f6f8;
}


/* PAGE */

.chat-page {
    width: 100%;
    height: 100dvh;

    display: flex;
    flex-direction: column;

    background: #f5f6f8;
}

.online-status.online {
    color: #00c853;
}

.online-status.offline {
    color: #999;
}

/* HEADER */

.chat-header {
    height: 76px;

    flex-shrink: 0;

    display: flex;
    align-items: center;

    gap: 14px;

    padding: 12px 24px;

    background: rgba(255, 255, 255, 0.96);

    border-bottom: 1px solid #e5e7eb;

    box-shadow: 0 2px 15px rgba(0, 0, 0, 0.04);

    z-index: 10;
}


.back-button {
    width: 40px;
    height: 40px;

    display: flex;
    align-items: center;
    justify-content: center;

    flex-shrink: 0;

    border-radius: 50%;

    color: #18181b;

    font-size: 26px;
    text-decoration: none;

    transition: background 0.2s;
}


.back-button:hover {
    background: #f0f0f0;
}


.avatar {
    width: 46px;
    height: 46px;

    flex-shrink: 0;

    display: flex;
    align-items: center;
    justify-content: center;

    border-radius: 50%;

    background: #18181b;
    color: white;

    font-size: 18px;
    font-weight: 600;
}


.user-info h2 {
    margin: 0;

    color: #18181b;

    font-size: 17px;
    font-weight: 650;
}


.user-info span {
    display: block;

    margin-top: 2px;

    color: #16a34a;

    font-size: 12px;
    font-weight: 500;
}


/* MESSAGE AREA */

.messages {
    flex: 1;
    min-height: 0;

    overflow-y: auto;
    overflow-x: hidden;

    display: flex;
    flex-direction: column;

    gap: 5px;

    padding: 28px max(24px, calc((100% - 900px) / 2));

    scroll-behavior: smooth;

    background:
        radial-gradient(
            circle at top left,
            rgba(0, 0, 0, 0.025),
            transparent 35%
        ),
        #f5f6f8;
}


/* MESSAGE ROW */

.message-row {
    width: 100%;

    display: flex;

    margin: 2px 0;
}


.message-row.mine {
    justify-content: flex-end;
}


.message-row.theirs {
    justify-content: flex-start;
}


/* BUBBLES */

.message-bubble {
    max-width: min(68%, 550px);

    padding: 10px 15px;

    font-size: 15px;
    line-height: 1.45;

    word-break: break-word;

    animation: messageAppear 0.15s ease;
}


.mine .message-bubble {
    background: #18181b;
    color: white;

    border-radius: 18px 18px 5px 18px;
}


.theirs .message-bubble {
    background: white;
    color: #18181b;

    border: 1px solid #e5e7eb;

    border-radius: 18px 18px 18px 5px;

    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.04);
}


@keyframes messageAppear {

    from {
        opacity: 0;
        transform: translateY(4px);
    }

    to {
        opacity: 1;
        transform: translateY(0);
    }

}


/* INPUT AREA */

.message-form {
    flex-shrink: 0;

    display: flex;
    align-items: center;

    gap: 10px;

    padding:
        12px
        max(20px, calc((100% - 1000px) / 2))
        calc(12px + env(safe-area-inset-bottom));

    background: rgba(255, 255, 255, 0.96);

    border-top: 1px solid #e5e7eb;

    box-shadow: 0 -5px 20px rgba(0, 0, 0, 0.03);
}


.message-input {
    flex: 1;

    min-width: 0;
    height: 50px;

    padding: 0 20px;

    border: 1px solid #dfe1e5;
    border-radius: 25px;

    outline: none;

    background: #f5f6f8;

    color: #18181b;

    font-size: 15px;

    transition:
        background 0.2s,
        border-color 0.2s,
        box-shadow 0.2s;
}


.message-input:focus {
    background: white;

    border-color: #b5b5b5;

    box-shadow: 0 0 0 3px rgba(0, 0, 0, 0.04);
}


.send-button {
    width: 50px;
    height: 50px;

    flex-shrink: 0;

    display: flex;
    align-items: center;
    justify-content: center;

    border: none;
    border-radius: 50%;

    background: #18181b;
    color: white;

    font-size: 17px;

    cursor: pointer;

    transition:
        transform 0.15s,
        background 0.15s;
}


.send-button:hover {
    background: #303034;
    transform: scale(1.04);
}


.send-button:active {
    transform: scale(0.94);
}


/* SCROLLBAR */

.messages::-webkit-scrollbar {
    width: 5px;
}


.messages::-webkit-scrollbar-thumb {
    background: #d4d4d4;
    border-radius: 20px;
}


/* MOBILE */

@media (max-width: 600px) {

    .chat-header {
        height: 66px;

        gap: 10px;

        padding: 8px 10px;
    }


    .back-button {
        width: 36px;
        height: 36px;

        font-size: 23px;
    }


    .avatar {
        width: 40px;
        height: 40px;

        font-size: 16px;
    }


    .user-info h2 {
        font-size: 16px;
    }


    .messages {
        padding: 16px 10px;
    }


    .message-bubble {
        max-width: 82%;

        padding: 9px 13px;

        font-size: 14px;
    }


    .message-form {
        gap: 8px;

        padding:
            9px
            10px
            calc(9px + env(safe-area-inset-bottom));
    }


    .message-input {
        height: 46px;

        padding: 0 16px;

        font-size: 16px;
    }


    .send-button {
        width: 46px;
        height: 46px;
    }

}


/* =========================
   DASHBOARD
========================= */

.dashboard-body {
    margin: 0;
    min-height: 100vh;

    background: #f4f5f7;

    font-family:
        -apple-system,
        BlinkMacSystemFont,
        "Segoe UI",
        sans-serif;

    color: #18181b;
}


.dashboard-page {
    min-height: 100vh;
}


/* HEADER */

.dashboard-header {
    height: 80px;

    display: flex;
    align-items: center;
    justify-content: space-between;

    padding: 0 32px;

    background: #ffffff;

    border-bottom: 1px solid #e5e7eb;

    box-sizing: border-box;
}


.dashboard-heading h1 {
    margin: 0;

    font-size: 22px;
    font-weight: 700;
}


.dashboard-heading p {
    margin: 4px 0 0;

    color: #71717a;

    font-size: 13px;
}


.logout-button {
    padding: 9px 16px;

    background: #18181b;
    color: #ffffff;

    border-radius: 10px;

    text-decoration: none;

    font-size: 14px;
    font-weight: 600;

    transition: 0.2s;
}


.logout-button:hover {
    background: #2b2b2f;

    transform: translateY(-1px);
}


/* CONTENT */

.dashboard-content {
    width: 100%;
    max-width: 700px;

    margin: 0 auto;

    padding: 38px 20px;

    box-sizing: border-box;
}


/* TITLE */

.users-title {
    display: flex;
    align-items: center;
    justify-content: space-between;

    margin-bottom: 14px;
}


.users-title h2 {
    margin: 0;

    font-size: 17px;
}


.active-count {
    color: #71717a;

    font-size: 13px;
}


/* USERS */

.users-list {
    display: flex;
    flex-direction: column;

    gap: 10px;
}


/* CARD */

.user-card {
    display: flex;
    align-items: center;

    gap: 14px;

    padding: 14px 16px;

    background: #ffffff;

    border: 1px solid #e5e7eb;
    border-radius: 16px;

    color: inherit;
    text-decoration: none;

    transition:
        transform 0.18s ease,
        box-shadow 0.18s ease;
}


.user-card:hover {
    transform: translateY(-2px);

    box-shadow:
        0 10px 30px rgba(0, 0, 0, 0.06);
}


/* AVATAR */

.user-avatar {
    position: relative;

    width: 48px;
    height: 48px;

    flex-shrink: 0;

    display: flex;
    align-items: center;
    justify-content: center;

    background: #18181b;
    color: white;

    border-radius: 50%;

    font-weight: 700;
}


/* ONLINE DOT */

.online-dot {
    position: absolute;

    right: 0;
    bottom: 1px;

    width: 11px;
    height: 11px;

    background: #22c55e;

    border: 2px solid white;
    border-radius: 50%;
}


/* USER DETAILS */

.user-details {
    flex: 1;

    display: flex;
    flex-direction: column;

    gap: 4px;
}


.user-details strong {
    font-size: 15px;
}


.user-details span {
    color: #22c55e;

    font-size: 12px;
}


/* ARROW */

.user-arrow {
    color: #a1a1aa;

    font-size: 26px;

    transition: transform 0.2s ease;
}


.user-card:hover .user-arrow {
    transform: translateX(4px);
}


/* EMPTY STATE */

.no-users {
    padding: 70px 20px;

    text-align: center;

    color: #71717a;
}


.no-users-icon {
    margin-bottom: 10px;

    font-size: 42px;
}


.no-users h3 {
    margin: 0 0 6px;

    color: #18181b;

    font-size: 16px;
}


.no-users p {
    margin: 0;

    font-size: 13px;
}


/* MOBILE */

@media (max-width: 600px) {

    .dashboard-header {
        height: 72px;

        padding: 0 18px;
    }


    .dashboard-heading h1 {
        font-size: 20px;
    }


    .dashboard-content {
        padding: 26px 14px;
    }


    .user-card {
        padding: 12px 14px;

        border-radius: 14px;
    }


    .user-avatar {
        width: 44px;
        height: 44px;
    }


    .logout-button {
        padding: 8px 13px;

        font-size: 13px;
    }

}


/* =========================
   AUTH / LOGIN
========================= */

.auth-body {
    margin: 0;
    min-height: 100vh;

    background: #f4f5f7;

    font-family:
        -apple-system,
        BlinkMacSystemFont,
        "Segoe UI",
        sans-serif;

    color: #18181b;
}


.auth-page {
    min-height: 100vh;

    display: flex;
    align-items: center;
    justify-content: center;

    padding: 24px;

    box-sizing: border-box;
}


.auth-card {
    width: 100%;
    max-width: 390px;

    padding: 38px;

    background: #ffffff;

    border: 1px solid #e5e7eb;
    border-radius: 24px;

    box-shadow:
        0 20px 60px rgba(0, 0, 0, 0.06);

    box-sizing: border-box;
}


/* LOGO */

.auth-brand {
    display: flex;
    align-items: center;
    gap: 12px;

    margin-bottom: 26px;
}

.auth-brand-icon {
    width: 52px;
    height: 52px;

    display: flex;
    align-items: center;
    justify-content: center;

    background: #18181b;
    color: white;

    border-radius: 50%;

    font-size: 20px;
    font-weight: 700;

    flex-shrink: 0;
}

.auth-brand-name {
    font-size: 24px;
    font-weight: 750;
    letter-spacing: -0.8px;
    color: #18181b;
}

/* HEADING */

.auth-heading {
    margin-bottom: 28px;
}


.auth-heading h1 {
    margin: 0;

    font-size: 28px;
    font-weight: 700;

    letter-spacing: -0.7px;
}


.auth-heading p {
    margin: 8px 0 0;

    color: #71717a;

    font-size: 14px;
    line-height: 1.5;
}


/* FORM */

.auth-form {
    display: flex;
    flex-direction: column;

    gap: 18px;
}


.auth-field {
    display: flex;
    flex-direction: column;

    gap: 8px;
}


.auth-field label {
    font-size: 13px;
    font-weight: 600;
}


.auth-field input {
    width: 100%;
    height: 48px;

    padding: 0 14px;

    background: #ffffff;

    border: 1px solid #d4d4d8;
    border-radius: 12px;

    outline: none;

    font-size: 14px;

    box-sizing: border-box;

    transition:
        border-color 0.2s ease,
        box-shadow 0.2s ease;
}


.auth-field input::placeholder {
    color: #a1a1aa;
}


.auth-field input:focus {
    border-color: #18181b;

    box-shadow:
        0 0 0 3px rgba(24, 24, 27, 0.08);
}


/* BUTTON */

.auth-button {
    width: 100%;
    height: 48px;

    margin-top: 4px;

    background: #18181b;
    color: #ffffff;

    border: none;
    border-radius: 12px;

    cursor: pointer;

    font-size: 14px;
    font-weight: 600;

    transition:
        transform 0.18s ease,
        background 0.18s ease;
}


.auth-button:hover {
    background: #2b2b2f;

    transform: translateY(-1px);
}


.auth-button:active {
    transform: translateY(0);
}


/* ERROR */

.auth-error {
    margin-bottom: 20px;

    padding: 11px 13px;

    background: #fef2f2;
    color: #b91c1c;

    border: 1px solid #fecaca;
    border-radius: 10px;

    font-size: 13px;
}


/* FOOTER */

.auth-footer {
    display: flex;
    justify-content: center;

    gap: 5px;

    margin-top: 26px;

    color: #71717a;

    font-size: 13px;
}


.auth-footer a {
    color: #18181b;

    font-weight: 600;
    text-decoration: none;
}


.auth-footer a:hover {
    text-decoration: underline;
}


/* MOBILE */

@media (max-width: 500px) {

    .auth-page {
        padding: 16px;
    }


    .auth-card {
        padding: 30px 24px;

        border-radius: 20px;
    }


    .auth-heading h1 {
        font-size: 25px;
    }

}

.auth-success {
    padding: 12px 14px;
    margin-bottom: 20px;

    background: #f0fff4;
    color: #16a34a;

    border: 1px solid #bbf7d0;
    border-radius: 10px;

    font-size: 14px;
}
